(window.webpackJsonp=window.webpackJsonp||[]).push([[129],{756:function(n,r){n.exports='\x3c!-- \r\ntitle: SIM800l\r\nsort: \r\n--\x3e \r\n# SIM800L入门\r\n\r\n![image-20201022135213683](https://gitee.com/nmdfzf404/Image-hosting/raw/master/2020/20201022135220.png)\r\n\r\n## 开机检查\r\n\r\n模块开机后应该执行下面初始化流程：\r\n```c\r\n1. AT                        // 测试串口通讯是否正常\r\n  > OK\r\n2. AT+CPIN?                 // 查询是否检测到SIM卡\r\n  > +CPIN: READY\r\n  > OK\r\n3. AT+CSQ                   // 查询信号质量\r\n  > +CSQ: 18,0\r\n  > OK\r\n4. AT+CREG?               // 查询模块是否注册网络\r\n  > +CREG: 0,1\r\n  > OK\r\n5. AT+CGATT?             // 查询模块是否GPRS\r\n  > +CGATT: 1\r\n  > OK\r\n```\r\n## 发送第一条短信\r\n\r\n```c\r\n1. AT+CMGF=1\t\t\t// 设定短信模式为TEXT\r\n2. AT+CSCA? \t\t\t// 模块会自动设置短信中心号码\r\n// AT+CSCA="+8613010980500"\t\t\t// 手动设置\r\n3. AT+CSGS="This is a HelloWorld Message."\r\n```\r\n\r\n'}}]);